// Extract message from various webhook payload formats
const input = $input.first().json;
const body = input.body || input;

let userPhone = '';
let userMessage = '';
let senderName = '';
let mediaType = 'text';
let mediaUrl = null;
let mediaMimeType = null;

// Format 1: Platform format { message, from_number, contact_name }
if (body.from_number && body.message) {
  userPhone = String(body.from_number);
  userMessage = String(body.message);
  senderName = body.contact_name || 'Customer';
  if (body.media && body.message_type !== 'text') {
    mediaType = body.message_type || 'media';
    mediaUrl = body.media.url || null;
    mediaMimeType = body.media.metadata?.mime_type || null;
  }
}
// Format 2: chat trigger { chatInput, sessionId, contact }
else if (body.chatInput !== undefined) {
  userMessage = body.chatInput || '';
  userPhone = body.contact?.phone || body.contact?.name || '60000000000';
  senderName = body.contact?.name || 'Customer';
  if (body.isMediaMessage && body.media) {
    mediaType = body.media.type || body.messageType || 'media';
    mediaUrl = body.media.url || null;
  }
}
// Format 3: simple { phone, message }
else if (body.phone && body.message) {
  userPhone = String(body.phone);
  userMessage = String(body.message);
  senderName = body.name || 'Customer';
}
// Format 4: WhatsApp Cloud API
else if (body.entry) {
  const value = body.entry[0]?.changes?.[0]?.value;
  const msg = value?.messages?.[0];
  if (!msg) return [];
  userPhone = msg.from;
  userMessage = msg.text?.body || msg.interactive?.button_reply?.title || '';
  senderName = value.contacts?.[0]?.profile?.name || 'Customer';
  if (msg.image) { mediaType = 'image'; mediaUrl = msg.image.url; mediaMimeType = msg.image.mime_type; }
  else if (msg.audio) { mediaType = 'audio'; mediaUrl = msg.audio.url; mediaMimeType = msg.audio.mime_type; }
}
else {
  userPhone = body.from || '60000000000';
  userMessage = body.text?.body || body.body || '';
  senderName = 'Customer';
}

// Normalize phone: strip @s.whatsapp.net, +, non-digits, 0-prefix
userPhone = String(userPhone).replace(/@.*$/, '').replace(/^\+/, '').replace(/\D/g, '');
if (userPhone.startsWith('0')) userPhone = '60' + userPhone.substring(1);

if (!userPhone || (!userMessage && mediaType === 'text')) return [];

return {
  json: {
    userPhone,
    userMessage: (userMessage || '').trim(),
    senderName: senderName || 'Customer',
    mediaType,
    mediaUrl,
    mediaMimeType,
    sessionId: body.sessionId || `${userPhone}_${new Date().toISOString().split('T')[0]}`,
    timestamp: new Date().toISOString(),
    raw: body
  }
};

// Merge text + transcribed audio + analyzed image into one message
const input = $input.first().json;
const pre = $('Message Preprocessing').first().json;

let finalMessage = pre.userMessage;
if (pre.mediaType === 'audio' && input.text) {
  finalMessage = input.text;
} else if (pre.mediaType === 'image' && (input.content || input.text)) {
  const analysis = input.content || input.text || '';
  finalMessage = analysis + (pre.userMessage ? ' | ' + pre.userMessage : '');
}

return {
  json: {
    ...pre,
    userMessage: finalMessage.trim(),
    mediaProcessed: true
  }
};

// Combine customer profile + history + current message
const lookupResult = $('Lookup Customer').first().json;
const historyResult = $('Get Conversation History').all();
const pre = $('Message Preprocessing').first().json;
const config = $('Config').first().json;

// Parse customer
let customer = Array.isArray(lookupResult) ? (lookupResult[0] || {}) : (lookupResult.body?.[0] || lookupResult || {});

// Build conversation history (oldest first)
let history = [];
if (historyResult && historyResult.length > 0) {
  // Some n8n versions wrap each row in .json
  const rows = historyResult.map(r => r.json || r).filter(r => r && r.conversation_text);
  rows.reverse(); // oldest first
  history = rows.map((r, i) => ({
    order: i + 1,
    text: r.conversation_text,
    intent: r.intent,
    timestamp: r.message_timestamp
  }));
}

const customerName = customer.customer_name || pre.senderName || 'Customer';
const customerType = customer.customer_type || 'normal';
const pricingLabel = customer.pricing_label || 'Retail';
const isRegistered = !!customer.is_registered;
const customerId = customer.customer_id || null;

return {
  json: {
    sessionId: pre.sessionId,
    senderPhone: pre.userPhone,
    senderName: customerName,
    userMessage: pre.userMessage,
    timestamp: pre.timestamp,
    mediaType: pre.mediaType,
    mediaUrl: pre.mediaUrl,
    customerId,
    customerName,
    customerType,
    pricingLabel,
    isRegistered,
    priceField: customerType === 'merchant' ? 'merchant_price' : 'normal_price',
    historyCount: history.length,
    historyText: history.map(h => h.text).join('\n'),
    historyJSON: history,
    isNewConversation: history.length === 0,
    SUPABASE_URL: config.SUPABASE_URL,
    SUPABASE_KEY: config.SUPABASE_KEY,
    WEBSITE_URL: config.WEBSITE_URL,
    WEBHOOK_SEND_URL: config.WEBHOOK_SEND_URL
  }
};

