// Prepare conversation log entry for storage
const humanizerOutput = $('Humanizer Agent').first().json;
const masterOutput = $('Master AI Agent').first().json;
const ctx = $('Parse Memory & Context').first().json;

const finalResponse = humanizerOutput.output || humanizerOutput.text || masterOutput.output || '';

// Extract tools used (from master agent)
let toolsUsed = [];
if (masterOutput.intermediateSteps && Array.isArray(masterOutput.intermediateSteps)) {
  toolsUsed = masterOutput.intermediateSteps
    .map(s => s.action?.tool || s.tool)
    .filter(Boolean);
}

// Detect intent simply
const lower = finalResponse.toLowerCase();
let intent = 'general';
if (lower.includes('cart') || lower.includes('purchase')) intent = 'cart';
else if (lower.includes('order') || lower.includes('tracking') || lower.includes('delivery')) intent = 'order';
else if (lower.includes('product') || lower.includes('rm') || lower.includes('component')) intent = 'product_search';
else if (lower.includes('return') || lower.includes('refund')) intent = 'return';

// Format conversation text for DB
const userMsg = ctx.userMessage.replace(/"/g, "'").substring(0, 1000);
const botMsg = finalResponse.replace(/"/g, "'").substring(0, 2000);
const conversationText = `user: ${userMsg} | assistant: ${botMsg}`;

return {
  json: {
    finalResponse,
    sessionId: ctx.sessionId,
    senderPhone: ctx.senderPhone,
    customerId: ctx.customerId,
    conversationText,
    intent,
    toolsUsed,
    mediaType: ctx.mediaType,
    mediaUrl: ctx.mediaUrl,
    timestamp: new Date().toISOString(),
    WEBHOOK_SEND_URL: ctx.WEBHOOK_SEND_URL
  }
};
